                requestAnimationFrame(() => {
                     setTimeout(() => {
                         el.style.transform = "translateX(-50%) scale(1) skewX(-15deg)";
                     }, 50);
                });
            }
            if(comboCount > GameStats.highestCombo) GameStats.highestCombo = comboCount;
